{
  "kind": "Plan",
  "name": "plan-02-chart-codex-values",
  "spec": {
    "phaseRef": "phase-04-credential-and-chart-wiring",
    "objective": "Add chart values for the Codex subagent image reference and the OpenAI credential Secret name so operators have first-class Helm surface for both. charts/tide/values.yaml gains images.codexSubagent (repository + tag, mirroring images.tideReporter shape) and a codexProviderSecretName key that documents the expected Secret name carrying OPENAI_API_KEY. No chart template changes are required — per-level image and ProviderSecretRef are Project-spec fields, not chart-managed ConfigMap keys — but the values additions provide clear guidance and enable future chart-managed defaults.",
    "wave": 1,
    "dependsOn": [],
    "filesTouched": [
      "charts/tide/values.yaml",
      "charts/tide/Chart.yaml"
    ]
  }
}

{
  "kind": "Plan",
  "name": "plan-03-jobspec-codex-creds",
  "spec": {
    "phaseRef": "phase-04-credential-and-chart-wiring",
    "objective": "Extend BuildJobSpec and its callers to perform vendor-aware credential injection. When the resolved vendor is 'openai', the credproxy sidecar is skipped and OPENAI_API_KEY is injected directly from the per-level ProviderSecretRef Secret into the subagent container env — the Codex CLI has no proxy-URL concept, so direct env injection is the documented API-key auth path. When vendor is 'anthropic', the existing credproxy path is unchanged. BuildOptions gains Vendor string and LevelProviderSecretRef string fields; dispatch_helpers.go provides the ResolveProviderSecretRef helper (from plan-01); all four planner-level controllers and the task controller are updated to pass both. Offline unit tests in jobspec_test.go cover the Codex credential branch.",
    "wave": 2,
    "dependsOn": [
      "plan-01-level-config-provider-secret"
    ],
    "filesTouched": [
      "internal/dispatch/podjob/jobspec.go",
      "internal/dispatch/podjob/jobspec_test.go",
      "internal/controller/task_controller.go",
      "internal/controller/milestone_controller.go",
      "internal/controller/phase_controller.go",
      "internal/controller/plan_controller.go"
    ]
  }
}

